+
+    let create = Command::new(bootstrap_python)
+        .arg("-m")
+        .arg("venv")
+        .arg(venv_dir)
+        .output()
+        .map_err(|err| {
+            format!("failed to bootstrap oracle venv via `{bootstrap_python} -m venv`: {err}")
